---@class StructFavorability
local StructFavorability = LxClass("StructFavorability", nil)
function StructFavorability:StructFavorability()
    self.heroRefId  = 0
    self.loveValue = 0
    self.loveLevel  =0
    self.interactionList = nil--1互动，2特写 3互动特写
end

function StructFavorability:CreateByPb(pb)
    self:OnUpdateByPb(pb)
end

function StructFavorability:OnUpdateByPb(pb)
    self.heroRefId = pb.heroRefId 
    self.loveValue = pb.loveValue
    self.loveLevel = pb.loveLevel
    local interact = {}
    for k ,v in ipairs(pb.interactionList or {}) do
        interact[v.effId] = v.status
    end
    self.interactionList = interact
    self:OnUpdateInteractionList(pb.interactionList)
    self.isUnlockSpAction = pb.isUnlockSpAction
    self.isUnlockCloseUpSp = pb.isUnlockCloseUpSp
end

function StructFavorability:OnUpdateInteractionList(interactList)
    local interact = {}
    for k ,v in ipairs(interactList or {}) do
        interact[v.effId] = v.status
    end
    self.interactionList = interact
end

return StructFavorability